// src/ephemeris/julian.ts
function julday(year, month, day, hour) {
  let u = year;
  if (month < 3) u -= 1;
  const u0 = u + 4712;
  let u1 = month + 1;
  if (u1 < 4) u1 += 12;
  let jd = Math.floor(u0 * 365.25) + Math.floor(30.6 * u1 + 1e-6) + day + hour / 24 - 63.5;
  let u2 = Math.floor(Math.abs(u) / 100) - Math.floor(Math.abs(u) / 400);
  if (u < 0) u2 = -u2;
  jd = jd - u2 + 2;
  if (u < 0 && u / 100 === Math.floor(u / 100) && u / 400 !== Math.floor(u / 400))
    jd -= 1;
  return jd;
}

